def gen(rng, size):
    def rand_bst(n):
        if n == 0:
            return []
        vals = rng.sample(range(-100000, 100001), n)
        order = vals[:]
        rng.shuffle(order)
        root = None
        nodes = {}
        def insert(v):
            nonlocal root
            if root is None:
                root = v
                nodes[v] = [None, None]
                return
            cur = root
            while True:
                l, r = nodes[cur]
                if v < cur:
                    if l is None:
                        nodes[cur][0] = v
                        nodes[v] = [None, None]
                        return
                    cur = l
                else:
                    if r is None:
                        nodes[cur][1] = v
                        nodes[v] = [None, None]
                        return
                    cur = r
        for v in order:
            insert(v)
        from collections import deque
        out = []
        q = deque([root])
        while q:
            cur = q.popleft()
            if cur is None:
                out.append(None)
                continue
            out.append(cur)
            cl, cr = nodes[cur]
            q.append(cl)
            q.append(cr)
        while out and out[-1] is None:
            out.pop()
        return out
    n1 = rng.randint(0, max(1, min(size, 2000)))
    n2 = rng.randint(0, max(1, min(size, 2000)))
    return [rand_bst(n1), rand_bst(n2)]

