class Solution:
    def getAllElements(self, root1, root2):
        vals = []
        def collect(node):
            if not node:
                return
            vals.append(node.val)
            collect(node.left)
            collect(node.right)
        collect(root1)
        collect(root2)
        vals.sort()
        return vals

